import torch
import numpy as np
from collections import deque
import hashlib

def load_maze():
    maze_data = torch.load('ctf_files/maze.pt')
    return maze_data.numpy()

def print_maze(maze):
    symbols = {0: ' ', 1: '█', 2: 'S', 3: 'E'}
    for row in maze:
        print(''.join(symbols[int(cell)] for cell in row))

def find_start_end(maze):
    start, end = None, None
    for i in range(len(maze)):
        for j in range(len(maze[0])):
            if maze[i][j] == 2:
                start = (i, j)
            elif maze[i][j] == 3:
                end = (i, j)
    return start, end

def get_neighbors(pos, maze):
    r, c = pos
    neighbors = []
    # Check up, down, left, right
    for dr, dc in [(-1,0), (1,0), (0,-1), (0,1)]:
        new_r, new_c = r + dr, c + dc
        if (0 <= new_r < len(maze) and 
            0 <= new_c < len(maze[0]) and 
            maze[new_r][new_c] != 1):
            neighbors.append((new_r, new_c))
    return neighbors

def bfs(maze, start, end):
    queue = deque([(start, [])])
    visited = {start}

    while queue:
        current, path = queue.popleft()
        if current == end:
            return path + [current]

        for neighbor in get_neighbors(current, maze):
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [current]))
    return None

def path_to_directions(path):
    directions = []
    for i in range(len(path)-1):
        curr_r, curr_c = path[i]
        next_r, next_c = path[i+1]

        if next_r < curr_r:  # Up
            directions.append('W')
        elif next_r > curr_r:  # Down
            directions.append('S')
        elif next_c < curr_c:  # Left
            directions.append('A')
        elif next_c > curr_c:  # Right
            directions.append('D')

    return ''.join(directions)

def main():
    print("Loading maze...")
    maze = load_maze()

    print("\nMaze visualization:")
    print_maze(maze)

    start, end = find_start_end(maze)
    print(f"\nStart position: {start}")
    print(f"End position: {end}")

    print("\nFinding shortest path...")
    path = bfs(maze, start, end)

    if path:
        print("\nPath coordinates:")
        print(path)

        directions = path_to_directions(path)
        print("\nPath as AWSD directions:")
        print(directions)

        # Calculate MD5 hash of the directions
        md5_hash = hashlib.md5(directions.encode()).hexdigest()
        print("\nFlag format:")
        print(f"flag{{{md5_hash}}}")
    else:
        print("No path found!")

if __name__ == "__main__":
    main()
